class Solution:
    def strangePrinter(self, s):
        if not s:
            return 0
        # collapse runs
        comp = []
        for ch in s:
            if not comp or comp[-1] != ch:
                comp.append(ch)
        t = ''.join(comp)
        n = len(t)
        import sys
        sys.setrecursionlimit(10000)
        from functools import lru_cache
        @lru_cache(maxsize=None)
        def solve(i, j):
            if i > j:
                return 0
            if i == j:
                return 1
            res = 1 + solve(i + 1, j)
            for k in range(i + 1, j + 1):
                if t[k] == t[i]:
                    res = min(res, solve(i + 1, k - 1) + solve(k, j))
            return res
        return solve(0, n - 1)

