var strangePrinter = function(s) {
    const comp = [];
    for (const ch of s) {
        if (comp.length === 0 || comp[comp.length - 1] !== ch) comp.push(ch);
    }
    const t = comp;
    const n = t.length;
    if (n === 0) return 0;
    const dp = Array.from({ length: n }, () => new Array(n).fill(0));
    for (let i = 0; i < n; i++) dp[i][i] = 1;
    for (let len = 2; len <= n; len++) {
        for (let i = 0; i + len - 1 < n; i++) {
            const j = i + len - 1;
            dp[i][j] = 1 + dp[i + 1][j];
            for (let k = i + 1; k <= j; k++) {
                if (t[k] === t[i]) {
                    const left = (k - 1 >= i + 1) ? dp[i + 1][k - 1] : 0;
                    dp[i][j] = Math.min(dp[i][j], left + dp[k][j]);
                }
            }
        }
    }
    return dp[0][n - 1];
};
